from itertools import islice, chain, repeat


def f1(f1_p1, f1_p2):
    for f1_v1, f1_v2 in zip(f1_p1, f1_p2):
        yield f1_v1
        yield f1_v2


def f2(f2_p1):
    f2_v1, f2_v2 = divmod(len(f2_p1), 2)
    f2_v3, f2_v2 = f2_v1 - (1 - f2_v2), f2_v1 + 1
    f2_v4 = f1(islice(f2_p1, None, f2_v3), repeat('('))
    f2_v5 = islice(f2_p1, f2_v3, f2_v2)
    f2_v6 = f1(repeat(')'), islice(f2_p1, f2_v2, None))
    return ''.join(chain(f2_v4, f2_v5, f2_v6))


print(f2(input()))
